/** VpnClientConfiguration for P2S client. */
export interface VpnClientConfiguration {
  /** The reference to the address space resource which represents Address space for P2S VpnClient. */
  vpnClientAddressPool?: AddressSpace;
  /** VpnClientRootCertificate for virtual network gateway. */
  vpnClientRootCertificates?: VpnClientRootCertificate[];
  /** VpnClientRevokedCertificate for Virtual network gateway. */
  vpnClientRevokedCertificates?: VpnClientRevokedCertificate[];
  /** VpnClientProtocols for Virtual network gateway. */
  vpnClientProtocols?: VpnClientProtocol[];
  /** VPN authentication types for the virtual network gateway.. */
  vpnAuthenticationTypes?: VpnAuthenticationType[];
  /** VpnClientIpsecPolicies for virtual network gateway P2S client. */
  vpnClientIpsecPolicies?: IpsecPolicy[];
  /** The radius server address property of the VirtualNetworkGateway resource for vpn client connection. */
  radiusServerAddress?: string;
  /** The radius secret property of the VirtualNetworkGateway resource for vpn client connection. We will no longer return radiusServerSecret in VirtualNetworkGateway Create/Update/Get/List/UpdateTags APIs response. Please use VirtualNetworkGateway ListRadiusSecrets API to fetch radius server secrets. */
  radiusServerSecret?: string;
  /** The radiusServers property for multiple radius server configuration. */
  radiusServers?: RadiusServer[];
  /** The AADTenant property of the VirtualNetworkGateway resource for vpn client connection used for AAD authentication. */
  aadTenant?: string;
  /** The AADAudience property of the VirtualNetworkGateway resource for vpn client connection used for AAD authentication. */
  aadAudience?: string;
  /** The AADIssuer property of the VirtualNetworkGateway resource for vpn client connection used for AAD authentication. */
  aadIssuer?: string;
  /** per ip address pool connection policy for virtual network gateway P2S client. */
  vngClientConnectionConfigurations?: VngClientConnectionConfiguration[];
}

export function vpnClientConfigurationSerializer(item: VpnClientConfiguration): any {
  return {
    vpnClientAddressPool: !item["vpnClientAddressPool"]
      ? item["vpnClientAddressPool"]
      : addressSpaceSerializer(item["vpnClientAddressPool"]),
    vpnClientRootCertificates: !item["vpnClientRootCertificates"]
      ? item["vpnClientRootCertificates"]
      : vpnClientRootCertificateArraySerializer(item["vpnClientRootCertificates"]),
    vpnClientRevokedCertificates: !item["vpnClientRevokedCertificates"]
      ? item["vpnClientRevokedCertificates"]
      : vpnClientRevokedCertificateArraySerializer(item["vpnClientRevokedCertificates"]),
    vpnClientProtocols: !item["vpnClientProtocols"]
      ? item["vpnClientProtocols"]
      : item["vpnClientProtocols"].map((p: any) => {
          return p;
        }),
    vpnAuthenticationTypes: !item["vpnAuthenticationTypes"]
      ? item["vpnAuthenticationTypes"]
      : item["vpnAuthenticationTypes"].map((p: any) => {
          return p;
        }),
    vpnClientIpsecPolicies: !item["vpnClientIpsecPolicies"]
      ? item["vpnClientIpsecPolicies"]
      : ipsecPolicyArraySerializer(item["vpnClientIpsecPolicies"]),
    radiusServerAddress: item["radiusServerAddress"],
    radiusServerSecret: item["radiusServerSecret"],
    radiusServers: !item["radiusServers"]
      ? item["radiusServers"]
      : radiusServerArraySerializer(item["radiusServers"]),
    aadTenant: item["aadTenant"],
    aadAudience: item["aadAudience"],
    aadIssuer: item["aadIssuer"],
    vngClientConnectionConfigurations: !item["vngClientConnectionConfigurations"]
      ? item["vngClientConnectionConfigurations"]
      : vngClientConnectionConfigurationArraySerializer(item["vngClientConnectionConfigurations"]),
  };
}

export function vpnClientConfigurationDeserializer(item: any): VpnClientConfiguration {
  return {
    vpnClientAddressPool: !item["vpnClientAddressPool"]
      ? item["vpnClientAddressPool"]
      : addressSpaceDeserializer(item["vpnClientAddressPool"]),
    vpnClientRootCertificates: !item["vpnClientRootCertificates"]
      ? item["vpnClientRootCertificates"]
      : vpnClientRootCertificateArrayDeserializer(item["vpnClientRootCertificates"]),
    vpnClientRevokedCertificates: !item["vpnClientRevokedCertificates"]
      ? item["vpnClientRevokedCertificates"]
      : vpnClientRevokedCertificateArrayDeserializer(item["vpnClientRevokedCertificates"]),
    vpnClientProtocols: !item["vpnClientProtocols"]
      ? item["vpnClientProtocols"]
      : item["vpnClientProtocols"].map((p: any) => {
          return p;
        }),
    vpnAuthenticationTypes: !item["vpnAuthenticationTypes"]
      ? item["vpnAuthenticationTypes"]
      : item["vpnAuthenticationTypes"].map((p: any) => {
          return p;
        }),
    vpnClientIpsecPolicies: !item["vpnClientIpsecPolicies"]
      ? item["vpnClientIpsecPolicies"]
      : ipsecPolicyArrayDeserializer(item["vpnClientIpsecPolicies"]),
    radiusServerAddress: item["radiusServerAddress"],
    radiusServerSecret: item["radiusServerSecret"],
    radiusServers: !item["radiusServers"]
      ? item["radiusServers"]
      : radiusServerArrayDeserializer(item["radiusServers"]),
    aadTenant: item["aadTenant"],
    aadAudience: item["aadAudience"],
    aadIssuer: item["aadIssuer"],
    vngClientConnectionConfigurations: !item["vngClientConnectionConfigurations"]
      ? item["vngClientConnectionConfigurations"]
      : vngClientConnectionConfigurationArrayDeserializer(
          item["vngClientConnectionConfigurations"],
        ),
  };
}

