/** VPN client root certificate of virtual network gateway. */
export interface VpnClientRootCertificate extends SubResource {
  /** The name of the resource that is unique within a resource group. This name can be used to access the resource. */
  name?: string;
  /** A unique read-only string that changes whenever the resource is updated. */
  readonly etag?: string;
  /** The certificate public data. */
  publicCertData: string;
  /** The provisioning state of the VPN client root certificate resource. */
  readonly provisioningState?: NetworkProvisioningState;
}

export function vpnClientRootCertificateSerializer(item: VpnClientRootCertificate): any {
  return {
    id: item["id"],
    properties: _vpnClientRootCertificatePropertiesSerializer(item),
    name: item["name"],
  };
}

export function vpnClientRootCertificateDeserializer(item: any): VpnClientRootCertificate {
  return {
    id: item["id"],
    ..._vpnClientRootCertificatePropertiesDeserializer(item["properties"]),
    name: item["name"],
    etag: item["etag"],
  };
}

/** Properties of SSL certificates of application gateway. */
export interface VpnClientRootCertificatePropertiesFormat {
  /** The certificate public data. */
  publicCertData: string;
  /** The provisioning state of the VPN client root certificate resource. */
  readonly provisioningState?: NetworkProvisioningState;
}

export function vpnClientRootCertificatePropertiesFormatSerializer(
  item: VpnClientRootCertificatePropertiesFormat,
): any {
  return { publicCertData: item["publicCertData"] };
}

export function vpnClientRootCertificatePropertiesFormatDeserializer(
  item: any,
): VpnClientRootCertificatePropertiesFormat {
  return {
    publicCertData: item["publicCertData"],
    provisioningState: item["provisioningState"],
  };
}

